mapper.select:
SELECT r.*, e.title AS exhibition_title, ts.slot_name, u.username FROM reservation r LEFT JOIN exhibition e ON r.exhibition_id = e.id LEFT JOIN time_slot ts ON r.time_slot_id = ts.id LEFT JOIN sys_user u ON r.user_id = u.id WHERE r.deleted = 0
AND r.user_id = #{userId}
AND r.exhibition_id = #{exhibitionId}
AND r.status = #{status}
AND u.username LIKE CONCAT('%', #{username}, '%')
ORDER BY r.create_time DESC
